var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"누구시죠?","JPN":"どなたですか？","ENG":"Who am I speaking to?","TWN":"你是誰？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DETECTIVE_FLOOR_ADMIN_NULL","text":{"KOREA":"다이애나 프리하트 부인?","JPN":"ダイアナ・プラハト夫人？","ENG":"Mrs. Diana Freeheart?","TWN":"黛安娜·普立哈特夫人？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DETECTIVE_FLOOR_ADMIN_NULL","text":{"KOREA":"실례합니다. 저희는 관리국 수사청에서 나왔습니다.","JPN":"いきなり失礼いたします。我々は管理局の捜査庁から参りました。","ENG":"Excuse me. We're investigators from the Administration.","TWN":"抱歉打擾了。我們來自管理局監察廳。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DETECTIVE_FLOOR_ADMIN_NULL","text":{"KOREA":"에드윈 프리하트. 이 사람이 부인의 남편 분이 맞습니까?","JPN":"エッドウィン・プラハト。この方が夫人のご主人で間違いはないでしょうか？","ENG":"Edwin Freeheart. Is this person your husband?","TWN":"艾德溫·普立哈特，請問這個人是你的丈夫嗎？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"네… 맞는데요.","JPN":"はい……そうですけど。","ENG":"Yes... He is.","TWN":"是的……沒錯。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"지금 연구소에서 근무중일 텐데, 뭣 때문에 찾으시죠?","JPN":"今は研究所で働いていますが、主人に何か？","ENG":"He's probably working at the lab right now. What brings you here?","TWN":"他現在應該在研究所。你們為什麼來找我？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DETECTIVE_FLOOR_ADMIN_NULL","text":{"KOREA":"유감스럽지만, 남편 분께선 지금 행방불명입니다.","JPN":"申し上げにくいのですが、ご主人は、現在行方不明になっています。","ENG":"We're sorry to tell you this news, but your husband is currently missing.","TWN":"抱歉，你的丈夫目前失蹤了。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"사기를 치고 싶은 거라면 다른 곳을 알아보시죠. 전 지금 철야근무로 사흘 밤을 새서 무척 피곤한 상태니까요.","JPN":"詐欺に付き合っている暇はないんです。私はこの三日間徹夜で働いて、すごく疲れているので。","ENG":"If you're looking to pull a scam, you've got the wrong person. I've been working for three nights straight and I'm extremely tired.","TWN":"如果你想詐騙，請另找他人。我已經連續三個晚上熬夜工作了，現在沒有精力聽你說這些。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DETECTIVE_FLOOR_ADMIN_NULL","text":{"KOREA":"에드윈 프리하트는 현재 관리국 기술보안정책을 위반한 중범죄자로 전세계에 수배된 상황입니다. 지금 TV를 켜면 확인하실 수 있을 거예요.","JPN":"エッドウィン・プラハト氏は、現在管理局のテクノロジー保安法に違反した重犯罪者として全世界で指名手配となっています。テレビでご確認した方が早いと思いますけどね。","ENG":"Edwin Freeheart is currently wanted worldwide for violating the Administration's technology security policies. You can see it on TV right now.","TWN":"艾德溫·普立哈特目前因違反管理局的技術安全政策而作為重犯在全球範圍內被通緝。夫人你現在打開電視，就可以看到相關報導。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"네? 그게… 무슨 소리죠? 잘 이해가 안 되는데.","JPN":"はい？　それは……どういうことなんですか？　ちょっと理解が追いつかないんですが。","ENG":"What? What are you talking about...? I don't quite understand.","TWN":"什麼？那個……你在說什麼？我不太明白。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DETECTIVE_FLOOR_ADMIN_NULL","text":{"KOREA":"자세한 설명은 내부기밀사항이라 말씀드리기 어렵군요.","JPN":"詳しい内容は機密事項ですので、お伝えするのは難しいのです。","ENG":"I'm afraid we can't share the details with you as they are classified.","TWN":"由於這是內部機密，很難為你詳細解釋。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DETECTIVE_FLOOR_ADMIN_NULL","text":{"KOREA":"만약 남편 분께서 돌아온다면 저희에게 알려주십시오. 더 위험한 일에 휘말리지 않도록 돕겠습니다.","JPN":"もしご主人がお戻りになられたら、私たちにお知らせください。これ以上深刻な事態に巻き込まれないよう、お手伝いいたしますので。","ENG":"If your husband returns, please let us know. We'll help you avoid getting involved in any potential danger.","TWN":"如果你丈夫回來了，請告訴我們。我們將幫助你，以防被捲入更加危險的事情。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"잠깐만요.","JPN":"ちょっと待ってください。","ENG":"Wait.","TWN":"等等。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"그 사람은 인명을 구하는 침식학 연구를 하고 있어요. 대체 그게 뭐가 잘못됐다는 거죠?","JPN":"あの人は人の命を助けるために侵食学を研究しているんです。いったいそれのなにが罪に問われるようなことなんでしょうか？","ENG":"He does research on the Corruption in order to save lives. What exactly did he do wrong?","TWN":"我丈夫正在進行的是拯救生命的侵蝕學研究。到底是發生了什麼問題？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DETECTIVE_FLOOR_ADMIN_NULL","text":{"KOREA":"어젯밤, 북방합의체가 이면세계에서 비밀리에 진행하고 있던 비인도적 실험이 적발됐어요.","JPN":"昨夜、北方合意体が裏世界で内密に進めていた非人道的実験について摘発がありました。","ENG":"Last night, covert human experiments conducted by the Northern Union in the Counterside were discovered.","TWN":"昨晚，北方和議會在異界秘密進行的非人道實驗被人舉報揭發。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DETECTIVE_FLOOR_ADMIN_NULL","text":{"KOREA":"침식체를 인위적으로 조작하는 대규모 프로젝트였죠. 거기엔 인체실험도 포함됩니다.","JPN":"人体実験が含まれた侵食体を人為的に改造する大規模プロジェクトです。","ENG":"It was a large-scale project aiming to artificially manipulate C.O.s. Which also involved human experimentation.","TWN":"這是一項旨在人為操縱侵蝕體的大型項目。其中還包括了人體實驗的部分。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"네? 그럴 리가요. 저희 남편은 북방합의체하고 아무런 접점이 없어요.","JPN":"え？　それはありえません。主人は北方合意体とはなんの関わりもないはずです。","ENG":"What? That can't be. My husband has no ties to the Northern Union.","TWN":"什麼？怎麼可能？我的丈夫與北方和議會沒有任何聯繫。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DETECTIVE_FLOOR_ADMIN_NULL","text":{"KOREA":"북방합의체는 에드윈 프리하트를 해당 프로젝트의 최고고문이자 책임자라고 발표했습니다.","JPN":"北方合意体はエッドウィン・プラハトが該当プロジェクトの最高顧問であり、責任者であるとの発表を出しています。","ENG":"The Northern Union announced that Edwin Freeheart was their chief consultant and supervisor of that project.","TWN":"北方和議會曾宣佈艾德溫·普立哈特擔任該專案的首席顧問兼負責人。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"제 남편은 가족을 아끼는 사람이에요.","JPN":"主人は家族をすごく大事にする人なんです。","ENG":"My husband is someone who cherishes his family.","TWN":"我的丈夫是一個很關心家庭的人。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"그런 사람이 가족을 속이면서 범죄를 저질렀다고요?","JPN":"そんな人が家族を騙して犯罪を犯したなんて信じられません！","ENG":"Are you saying that such a person committed crimes while deceiving his family?","TWN":"這樣的人，怎麼會瞞著家人去犯罪？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DETECTIVE_FLOOR_ADMIN_NULL","text":{"KOREA":"북방합의체는 수단방법을 가리지 않는 편이죠. 저희는 그가 일방적으로 이용당했을 가능성도 배제하지 않습니다.","JPN":"北方合意体は目的のためなら手段は選びません。我々も彼が一方的に利用されている可能性を排除してはいません。","ENG":"The Northern Union is known for not hesitating to use any means necessary. We haven't ruled out the possibility that he may have been taken advantage of by them.","TWN":"北方和議會不擇手段。我們不排除他被單方面利用的可能性。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DETECTIVE_FLOOR_ADMIN_NULL","text":{"KOREA":"그래서 도와드리려는 겁니다. 만일 남편 분과 연락이 닿게 된다면 저희가 말씀드리는 지침을 따라 주십시오.","JPN":"だからこそ、手を差し伸べようとしているのです。もしご主人と連絡が取れた場合は、我々の方針に従っていただけますか。","ENG":"That's why we're here to help. If you ever get in touch with your husband, please follow the instructions we give you.","TWN":"這就是為什麼我們想幫助你。如果你能夠聯繫到你的丈夫，請按照我們給你的指示進行操作。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"잠시… 잠시만요.","JPN":"あ……ちょっと待ってください。","ENG":"Wait... hold on.","TWN":"等……等一下。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"딸 애가 있는 병원에서 연락이 왔어요.","JPN":"娘の病院から電話が。","ENG":"I'm getting a call from the hospital where my daughter is.","TWN":"是女兒醫院的號碼。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"전화 받았어요.","JPN":"はい、もしもし。","ENG":"Hello?","TWN":"我接個電話。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"DETECTIVE_FLOOR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};